import java.util.*;

class FoodRatings {
    HashMap<String, Integer> food_ratings = new HashMap<>();
    HashMap<String, String> highest_rated = new HashMap<>();

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        for (int i = 0; i < foods.length; ++i) {
            food_ratings.put(foods[i], ratings[i]);
            highest_rated.putIfAbsent(cuisines[i], "");
            if (highest_rated.get(cuisines[i]).equals("") ||
                ratings[i] > food_ratings.get(highest_rated.get(cuisines[i])) ||
                (ratings[i] == food_ratings.get(highest_rated.get(cuisines[i])) && foods[i].compareTo(highest_rated.get(cuisines[i])) < 0)) {
                highest_rated.put(cuisines[i], foods[i]);
            }
        }
    }

    public void changeRating(String food, int newRating) {
        String cuisine = "";
        for (Map.Entry<String, String> it : highest_rated.entrySet()) {
            if (it.getValue().equals(food)) {
                cuisine = it.getKey();
                break;
            }
        }
        food_ratings.put(food, newRating);
        for (Map.Entry<String, Integer> it : food_ratings.entrySet()) {
            if (highest_rated.get(cuisine).equals(food) ||
                (newRating > it.getValue() && cuisine.equals(it.getKey())) ||
                (newRating == it.getValue() && food.compareTo(it.getKey()) < 0)) {
                highest_rated.put(cuisine, food);
            }
        }
    }

    public String highestRated(String cuisine) {
        return highest_rated.get(cuisine);
    }
}
```


